#include <stdio.h>

int main() {
    int a, b;
    scanf("%d %d", &a, &b);
    int i = 1;
    while (1) {
        if (i % 2 != 0) {
            if (a < i) {
                printf("Vladik\n");
                break;
            }
            a -= i;
        } else {
            if (b < i) {
